$(function(){var popup_window=null;var popup_check_interval=null;$("#join-event-link").off("click").on("click",function(e){e.preventDefault();var url=$(this).attr('href');$.ajax({"method":"GET","url":url,"success":function(json){if(json.redirect_url){window.location.href=json.redirect_url;}},"error":function(jqXHR,textStatus,errorThrown){$("body").addClass("has-join-popup");if(jqXHR.responseText==='user_not_allowed'){$("#join-video-popupmodal").removeAttr("hidden");}else if(jqXHR.responseText==='missing_configuration'){$("#join-video-popupmodal-missing-config").removeAttr("hidden");}}});});$('#join-online-close-button').click(function(){$('#join-video-popupmodal').attr('hidden','true');$("body").removeClass("has-join-popup");});$('#join-online-close-button-missing-config').click(function(){$('#join-video-popupmodal-missing-config').attr('hidden','true');$("body").removeClass("has-join-popup");});});;